var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"흐흠~ 오늘도 계좌에 주님의 은총이 가득하구나!","JPN":"ふふ～ん、今日も口座に主の恩寵がたくさん！","ENG":"Haha! Another day, another divine blessing deposited into my account!","TWN":"哼哼～今天帳戶裡也充滿了主的恩寵啊！"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_QM","text":{"KOREA":"<color=#ffd34c>상황 보고 바람.</color>","JPN":"<color=#ffd34c>状況報告求む。</color>","ENG":"<color=#ffd34c>Report status.</color>","TWN":"<color=#ffd34c>請彙報情況。</color>"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"칫, 일 끝난 건 귀신같이 아네.","JPN":"ちっ、どうして仕事が終わったってわかったんだよ？","ENG":"Tch, of course she'd check in the second I finish.","TWN":"嘖，竟然馬上就知道任務完成了。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"상황 보고라니, 너무 딱딱한 거 아냐?","JPN":"状況報告って、堅苦しすぎだろ。","ENG":"Report status? That's way too formal.","TWN":"還要彙報情況，未免太正式了吧？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"<color=#ffd34c>일정 완료했습니다. ^^</color>","JPN":"<color=#ffd34c>仕事終わりました(^―^)</color>","ENG":"<color=#ffd34c>Mission complete. :)</color>","TWN":"<color=#ffd34c>任務已完成。^^</color>"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"처치 곤란이었던 성수들도 전부 치웠고, 오늘은 좋은 호텔에서 자볼까?","JPN":"持て余してた聖水も全部処理したし、今日はいいホテルに泊まっちゃうか？","ENG":"All the leftover holy water is taken care of, so I should splurge on a nice hotel tonight.","TWN":"那些難纏的聖獸也都處理掉了，今天要不要去找個好飯店住一晚？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"바르샤바에서 유명한 호텔이 있다고 들었는데~","JPN":"ワルシャワに有名なホテルがあるって聞いたんだよね～","ENG":"I heard there's a famous one in Warszawa...","TWN":"聽說華沙有一家很有名的飯店～"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"네네. 루시아 릿지 받았습니다.","JPN":"はいはい。ルシア・リッジです。","ENG":"Yes, Lucia Ridge speaking.","TWN":"好的，收到。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"후훗. 잔뜩 심통이 난 표정이네, 우리 멍멍이?","JPN":"ふふっ。苦虫をつぶしたような顔してるわね、ワンちゃん。","ENG":"Haha. You look so grumpy, Puppy.","TWN":"噗。生什麼悶氣呢，我的狗狗？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그야…… 이제 좀 쉬나 했더니 바로 연락하셨으니까요.","JPN":"そりゃ……休もうかなってところに連絡してきたらね。","ENG":"Well, of course I do. I was just about to relax, and then you called.","TWN":"那是因為……我剛想休息一下，你就聯絡我了。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"직장 상사가 퇴근 시간 이후까지 간섭하는데, 어떻게 좋아하겠어요?","JPN":"職場の上司が退勤後までちょっかい出してくるのに、喜ぶわけないでしょう？","ENG":"What kind of employee likes a boss who bothers her after hours?","TWN":"誰會喜歡下班後還要工作呢？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그리고, 저 좀 그만 훔쳐보라고 말씀드렸잖아요.","JPN":"それと、覗き見はやめてくださいって言いましたよね。","ENG":"Also, I've told you before to quit spying on me.","TWN":"還有，我不是說了不要再偷看我了嗎？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그거 범죄예요. 범죄. 알아요?","JPN":"それ犯罪ですよ、犯罪。わかってるんですか？","ENG":"That's illegal. You do know that, right?","TWN":"那是犯罪，是犯罪。知道嗎？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"미안해. 그럴 생각은 없었어.","JPN":"ごめんね、そういうつもりはなかったの。","ENG":"Sorry, I didn't mean to.","TWN":"對不起，我不是故意的。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"하지만 부하 직원이 일을 잘하고 있는지 확인해야 하는 건 상사의 의무인걸?","JPN":"でも上司には部下がちゃんと仕事をしてるのか確認する義務があるでしょう？","ENG":"But it's my duty to check in on my subordinates, isn't it?","TWN":"但是，確認下屬是否在好好工作是上司的義務吧？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"제가 샤워하는 것까지 몰래 사진 찍어서 보관하시잖아요.","JPN":"私がシャワーを浴びてるところまでこっそり撮影してるじゃないですか。","ENG":"You literally take secret photos of me in the shower.","TWN":"你還偷偷拍我洗澡的照片保存起來。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그게 어떻게 상사의 의무예요? 범죄지.","JPN":"何が上司の義務ですか。犯罪です。","ENG":"How is that a duty? That's a crime.","TWN":"那怎麼能是上司的義務？那是犯罪。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"물가에 내놓은 아이를 지켜보는 심정이라고 생각해 줘.","JPN":"子どもを見守る親心だと思ってほしいわね。","ENG":"Think of it as watching over a reckless child near the water.","TWN":"就當我是在擔心在水邊玩耍的下屬吧。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"하아, 됐어요. 무슨 일이에요?","JPN":"もういいです。何の用ですか？","ENG":"*Sigh* Fine. What do you want?","TWN":"哀，算了。有什麼事嗎？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"돈은 내일 보낼게요.","JPN":"お金なら明日送りますよ。","ENG":"I'll send the money tomorrow.","TWN":"錢明天會匯給你。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"설마 생활비를 다 쓰신 건 아니죠?","JPN":"まさか、もう生活費全部使っちゃったわけじゃないですよね？","ENG":"Don't tell me you spent all of your living expenses again?","TWN":"不會是把生活費全花光了吧？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"생활비는 조금 아슬아슬하지만, 문제없는 수준이야.","JPN":"生活費はギリギリだけど、問題ないわ。","ENG":"It's a little tight, but I'm managing.","TWN":"生活費有點緊張，但還在可控範圍內。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"중요한 의뢰가 들어와서, 바로 출발해 줘야겠어.","JPN":"重要な依頼が入って、すぐに出発してもらいたいの。","ENG":"But I have an important job for you, and you need to leave right away.","TWN":"有重要的委託來了，必須馬上出發。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"네? 지금요?","JPN":"えっ？　今からですか？","ENG":"What? Now?","TWN":"蛤？現在嗎？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};